C5='const html="<!DOCTYPE html><html><head><meta charset=\'UTF-8\'/>"+hi+"<style>"+css+"</style></head><body><div class=\'canvas\'>"+leftPhone+arrow+rightPhone+"</div></body></html>";\nconst browser=await chromium.launch();\nconst ctx=await browser.newContext({viewport:{width:1800,height:900},deviceScaleFactor:2});\nconst page=await ctx.newPage();\nawait page.setContent(html,{waitUntil:"networkidle"});\nawait page.waitForFunction(()=>document.fonts.ready.then(()=>true));\nawait page.waitForTimeout(2000);\nconst el=await page.locator(".canvas").elementHandle();\nconst outPath=join(OUT_DIR,c.outName+".png");\nawait el.screenshot({path:outPath,omitBackground:false});\nawait browser.close();\nconsole.log("Saved:"+outPath);\n'; open('.github/scripts/render-final.js','a').write(C5); print('p5 ok')